import React, { useMemo } from "react";
import { PageTitle } from '@/components/ui/Typography';
import { useAttendeesStore, useLoadingStore } from "@/store";
import { AttendeeServices } from "@/api";
import { ApiGlobalStateManager } from "@/lib/api-state";
import { StatusMessage } from "@/components/StatusMessage";
import { PageCard } from "@/components/PageCard";
import { TableContainer, Paper, Table, TableHead, TableRow, TableCell, TableBody, Box, Typography, Divider, Chip } from "@mui/material";
import { AttendeeBasicInfo } from "@/types/attendee.types";
import { getEventId } from "@/constants/ApiConstants";
import { CallStatus } from "@/types/api.types";
import { calculateDonationTotal } from '@/utils/eventCalculations';
import { foodColors } from '@/constants/ThemeConstants';

// Helper function to get food preference colors
const getFoodColor = (food: string): { bg: string; text: string } => {
    const colorMap: { [key: string]: { bg: string; text: string } } = {
        Veg: { bg: '#e8f5e9', text: '#2e7d32' },
        NonVeg: { bg: '#ffebee', text: '#c62828' },
        Null: foodColors.grey,
    };
    return colorMap[food] || foodColors.orange;
};

// Helper function to calculate donation total from string format
export const CheckinStatus: React.FunctionComponent = () => {
    const eventId = getEventId();
    const { attendeeListState, setAttendeeListState } = useAttendeesStore();
    const { setLoading } = useLoadingStore();
    const hasFetchedRef = React.useRef<boolean>(false);

    React.useEffect(() => {
        if (
            eventId && 
            !hasFetchedRef.current &&
            attendeeListState.status !== CallStatus.Success && 
            attendeeListState.status !== CallStatus.InProgress
        ) {
            hasFetchedRef.current = true;
            ApiGlobalStateManager(AttendeeServices.GetAttendees(eventId), setAttendeeListState);
        }
    }, [eventId, attendeeListState.status]);

    // Show/hide global loading based on attendee list status
    React.useEffect(() => {
        if (attendeeListState.status === CallStatus.InProgress) {
            setLoading(true, 'Loading statistics...');
        } else {
            setLoading(false);
        }
        
        // Cleanup on unmount
        return () => {
            setLoading(false);
        };
    }, [attendeeListState.status, setLoading]);

    const activeAttendees = useMemo(() => {
        if (!Array.isArray(attendeeListState.data)) {
            return [];
        }

        return attendeeListState.data.filter((attendee: AttendeeBasicInfo) => (attendee.headCount ?? 1) > 0);
    }, [attendeeListState.data]);

    // Compute check-in status by school from attendee list
    const checkinStatusBySchool = useMemo(() => {
        if (activeAttendees.length === 0) return [];

        // Group by school
        const schoolGroups: { [key: string]: AttendeeBasicInfo[] } = {};
        activeAttendees.forEach((attendee: AttendeeBasicInfo) => {
            const school = attendee.profile?.firstJnvName || 'Unknown';
            if (!schoolGroups[school]) {
                schoolGroups[school] = [];
            }
            schoolGroups[school].push(attendee);
        });

        // Calculate stats for each school
        const stats = Object.entries(schoolGroups).map(([schoolName, attendees]) => ({
            schoolName,
            totalAttendees: attendees.length,
            venueCheckedIn: attendees.filter(a => a.checkedInAt && a.checkedInAt > 0).length
        }));

        // Add "All" row
        const totalAttendees = activeAttendees.length;
        const totalCheckedIn = activeAttendees.filter(
            (a: AttendeeBasicInfo) => a.checkedInAt && a.checkedInAt > 0
        ).length;

        stats.push({
            schoolName: 'All',
            totalAttendees,
            venueCheckedIn: totalCheckedIn
        });

        // Sort by school name
        return stats.sort((a, b) => a.schoolName.localeCompare(b.schoolName));
    }, [activeAttendees]);

    return (
        <>
            {/* Only show error messages, backdrop spinner handles loading state */}
            {attendeeListState.status === CallStatus.Failure || attendeeListState.status === CallStatus.BadRequest ? (
                <PageCard>
                    <PageTitle>Attendance Statistics</PageTitle>
                    <StatusMessage
                        notStartedMessage=""
                        successMessage=""
                        failureMessage="Failed to load attendee data"
                        currentStatus={attendeeListState.status}
                        correlationId={attendeeListState.correlationId}
                    />
                </PageCard>
            ) : null}

            {/* Don't show any content until data is loaded */}
            {attendeeListState.status !== CallStatus.Success || !Array.isArray(attendeeListState.data) ? null : (
            <>
            {/* Summary Section */}
            <Paper sx={{ p: 2, mb: 2 }}>
                <Typography variant="h6" gutterBottom sx={{ fontSize: '1rem', fontWeight: 600 }}>
                    Attendance Summary
                </Typography>
                <Box sx={{ display: 'flex', gap: 3, flexWrap: 'wrap', mb: 1 }}>
                    <Box>
                        <Typography variant="body2" color="text.secondary">
                            Registered
                        </Typography>
                        <Typography variant="h6" sx={{ fontSize: '1.5rem', fontWeight: 600, color: 'primary.main' }}>
                            {activeAttendees.length}
                        </Typography>
                    </Box>
                    <Box>
                        <Typography variant="body2" color="text.secondary">
                            Head Count
                        </Typography>
                        <Typography variant="h6" sx={{ fontSize: '1.5rem', fontWeight: 600, color: 'primary.main' }}>
                            {activeAttendees.reduce((sum: number, a: AttendeeBasicInfo) => sum + (a.headCount ?? 1), 0)}
                        </Typography>
                    </Box>
                    <Box>
                        <Typography variant="body2" color="text.secondary">
                            Checked In
                        </Typography>
                        <Typography variant="h6" sx={{ fontSize: '1.5rem', fontWeight: 600, color: 'success.main' }}>
                            {activeAttendees.filter((a: AttendeeBasicInfo) => (a.checkedInAt ?? 0) > 0).length}
                        </Typography>
                    </Box>
                    <Box>
                        <Typography variant="body2" color="text.secondary">
                            At Venue
                        </Typography>
                        <Typography variant="h6" sx={{ fontSize: '1.5rem', fontWeight: 600, color: 'success.main' }}>
                            {activeAttendees
                                .filter((a: AttendeeBasicInfo) => (a.checkedInAt ?? 0) > 0)
                                .reduce((sum: number, a: AttendeeBasicInfo) => sum + (a.headCount ?? 1), 0)}
                        </Typography>
                    </Box>
                    <Box>
                        <Typography variant="body2" color="text.secondary">
                            Donations
                        </Typography>
                        <Typography variant="h6" sx={{ fontSize: '1.5rem', fontWeight: 600, color: 'secondary.main' }}>
                            ₹{activeAttendees.reduce((sum: number, a: AttendeeBasicInfo) => sum + calculateDonationTotal(a.donation), 0)}
                        </Typography>
                    </Box>
                </Box>
                
                {/* Food Preferences Breakdown */}
                {activeAttendees.length > 0 && (
                    <>
                        <Divider sx={{ my: 1.5 }} />
                        <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
                            Food Preferences
                        </Typography>
                        <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap' }}>
                            {(() => {
                                const foodCounts: { [key: string]: number } = {};
                                activeAttendees.forEach((attendee: AttendeeBasicInfo) => {
                                    const food = attendee.foodPreference || 'Null';
                                    foodCounts[food] = (foodCounts[food] || 0) + 1;
                                });
                                return Object.entries(foodCounts)
                                    .sort(([, a], [, b]) => b - a)
                                    .map(([food, count]) => {
                                        const colors = getFoodColor(food);
                                        return (
                                            <Chip 
                                                key={food}
                                                label={`${food}: ${count}`}
                                                size="small"
                                                sx={{
                                                    backgroundColor: colors.bg,
                                                    color: colors.text,
                                                    fontWeight: 500,
                                                    borderColor: colors.text,
                                                }}
                                                variant="outlined"
                                            />
                                        );
                                    });
                            })()}
                        </Box>
                    </>
                )}
            </Paper>

            <TableContainer component={Paper}>
                <Table sx={{ minWidth: 300 }}>
                    <TableHead sx={{ backgroundColor: 'action.hover' }}>
                        <TableRow>
                            <TableCell>
                                <Typography variant="subtitle2" sx={{ fontWeight: 'bold' }}>School</Typography>
                            </TableCell>
                            <TableCell align="right">
                                <Typography variant="subtitle2" sx={{ fontWeight: 'bold' }}>Checkin Status</Typography>
                            </TableCell>
                        </TableRow>
                    </TableHead>
                    <TableBody>
                        {checkinStatusBySchool.map((row) => (
                            <TableRow key={row.schoolName} sx={{ '&:last-child td, &:last-child th': { border: 0 } }}>
                                <TableCell component="th" scope="row">
                                    <Typography variant="body2">{row.schoolName}</Typography>
                                </TableCell>
                                <TableCell align="right">{row.venueCheckedIn} / {row.totalAttendees}</TableCell>
                            </TableRow>
                        ))}
                    </TableBody>
                </Table>
            </TableContainer>
            </>
            )}
        </>
    );
};
